  'hi': {
    'step_analysis': 'कदम दर कदम समाधान विश्लेषण',
    'step_analysis_desc': 'यह समाधान के "कैसे" और "क्यों" को गहराई से सिखाता है, प्रत्येक समस्या के तार्किक परतों को अलग करके।',
    'ai_teacher_desc': 'भले ही उसका नाम शिक्षक हो, वह वास्तव में आपका सबसे अच्छा दोस्त है! वह आपसे सवालों के बारे में बात करता है, एक दोस्ताना भाषा में समझाता है। वह आपको छोटे-छोटे सुरागों से जवाब खोजने देता है।',
    'worlds_strongest_ai': 'दुनिया की सबसे शक्तिशाली बुद्धिमत्ता',
    'worlds_strongest_ai_desc': 'यह दुनिया के सबसे अच्छे और सबसे उन्नत कृत्रिम बुद्धिमत्ता मॉडल को आपकी सेवा में असीमित रूप से प्रस्तुत करता है। इन विशाल मॉडलों की संयुक्त शक्ति के साथ, एक ऐसा अनुभव आपका इंतजार कर रहा है जहाँ आपको हर प्रश्न का उच्चतम गुणवत्ता और सबसे बुद्धिमान उत्तर मिलेगा।',
    'active_learning': 'सक्रिय शिक्षण और सुदृढीकरण',
    'active_learning_desc': 'सीखी गई जानकारी को सुदृढ़ करने के लिए, हल किए गए प्रत्येक प्रश्न के लिए तुरंत समान नए प्रश्न उत्पन्न किए जाते हैं।',
    'smart_info_cards': 'स्मार्ट फ्लैशकार्ड',
    'smart_info_cards_desc': 'यह पूछे गए प्रत्येक प्रश्न का गहराई से विश्लेषण करता है, संबंधित विषय की मूल अवधारणाओं, सूत्रों और सबसे महत्वपूर्ण जानकारी को स्कैन करता है; फिर यह इस डेटा को व्यवस्थित डिजिटल कार्ड के रूप में प्रस्तुत करता है।',
    'gamified_learning': 'गेमिफाइड लर्निंग',
    'gamified_learning_desc': 'सीखी गई जानकारी को इंटरैक्टिव गेमिफिकेशन तकनीकों के साथ जोड़कर, यह प्रक्रिया को यादगार और प्रतिस्पर्धी मनोरंजन में बदल देता है।',
    'terms_header': '📋 उपयोग की शर्तें और नियम',
    'terms_intro': 'QuAlsar का उपयोग करके, आप इन शर्तों का पालन करने के लिए सहमत होते हैं। यह प्लेटफ़ॉर्म उन्नत कृत्रिम बुद्धिमत्ता मॉडल का उपयोग करके आपको शैक्षणिक सहायता प्रदान करने वाला एक उपकरण है।',
    'service_scope_title': 'सेवा का दायरा और कृत्रिम बुद्धिमत्ता की जिम्मेदारी',
    'service_scope_body': 'QuAlsar; ChatGPT-5 Pro, Claude Max, Super Grok और अन्य तृतीय-पक्ष मॉडल का उपयोग करता है। कृत्रिम बुद्धिमत्ता द्वारा उत्पन्न प्रतिक्रियाओं की 100% सटीकता की गारंटी नहीं है। प्रस्तुत समाधान "सुझाव" के रूप में हैं; आपके शैक्षणिक निर्णयों में अंतिम जिम्मेदारी उपयोगकर्ता की है।',
    'usage_purpose_title': 'उपयोग का उद्देश्य',
    'usage_purpose_body': 'एप्लिकेशन को सीखने को आसान बनाने के लिए डिज़ाइन किया गया है। परीक्षा सुरक्षा का उल्लंघन करने वाले उपयोग या प्लेटफ़ॉर्म को रिवर्स-इंजीनियरिंग विधियों से कॉपी करना सख्त वर्जित है।',
    'subscription_title': 'सदस्यता और भुगतान',
    'subscription_body': 'प्रीमियम सदस्यताएं इन-ऐप खरीदारी नियमों के अधीन हैं। खरीद पूरी होने के बाद, वापसी प्रक्रियाएं Apple App Store और Google Play Store की नीतियों के माध्यम से की जाती हैं।',
    'privacy_header': ' 🔐 गोपनीयता और डेटा सुरक्षा सूचना',
    'privacy_intro': 'QuAlsar आपकी गोपनीयता को आपकी सफलता जितना ही महत्व देता है। हम नीचे पारदर्शी रूप से बताते हैं कि आपके डेटा को कैसे संसाधित किया जाता है।',
    'privacy_data_types': ' 📸 छवि डेटा: आपके द्वारा विश्लेषण के लिए अपलोड की गई तस्वीरें केवल संबंधित कृत्रिम बुद्धिमत्ता मॉडल को विश्लेषण के लिए भेजी जाती हैं और प्रक्रिया पूरी होने के बाद सुरक्षित रूप से संसाधित की जाती हैं।\n\n📊 उपयोग डेटा: आपके अनुभव को बेहतर बनाने के लिए गुमनाम उपयोग आँकड़े एकत्र किए जा सकते हैं।',
